let SearchPageVisits =
    pageViews
    | where timestamp {TimeRange}
    | where url contains "/search"
    | summarize by operation_Id;
let TotalVisits = toscalar(SearchPageVisits | count);
let CaseNumberSearches =
    customEvents
    | where timestamp {TimeRange}
    | where name == "search"
    | where isnotempty(tostring(customDimensions.caseNumber))
    | project operation_Id;
let CaseNumberClosedVisits = toscalar(
    CaseNumberSearches
    | join kind=inner SearchPageVisits on operation_Id
    | summarize by operation_Id
    | count
);
print
    TotalVisits = TotalVisits,
    CaseNumberClosedVisits = CaseNumberClosedVisits,
    CaseNumberSearchRate = round(iif(TotalVisits > 0, todouble(CaseNumberClosedVisits) / todouble(TotalVisits) * 100, 0.0), 1)

let CaseNumberWithClosedEvents =
    customEvents
    | where timestamp {TimeRange}
    | where name == "search"
    | where isnotempty(tostring(customDimensions.caseNumber))
    | where tostring(customDimensions.excludeClosedCases) == "false"
    | project operation_Id;
let TotalCaseNumberSearchVisits = toscalar(
    customEvents
    | where timestamp {TimeRange}
    | where name == "search"
    | where isnotempty(tostring(customDimensions.caseNumber))
    | summarize by operation_Id
    | count
);
let ClosedCaseNumberVisits = toscalar(
    CaseNumberWithClosedEvents
    | summarize by operation_Id
    | count
);
print
    TotalCaseNumberVisits = TotalCaseNumberSearchVisits,
    ClosedCaseNumberVisits = ClosedCaseNumberVisits,
    Rate = round(iif(TotalCaseNumberSearchVisits > 0, todouble(ClosedCaseNumberVisits) / todouble(TotalCaseNumberSearchVisits) * 100, 0.0), 1)

let OtherWithClosedEvents =
    customEvents
    | where timestamp {TimeRange}
    | where name == "search"
    | where isempty(tostring(customDimensions.caseNumber))
    | where tostring(customDimensions.excludeClosedCases) == "false"
    | project operation_Id;
let TotalOtherVisits = toscalar(
    customEvents
    | where timestamp {TimeRange}
    | where name == "search"
    | where isempty(tostring(customDimensions.caseNumber))
    | summarize by operation_Id
    | count
);
let ClosedOtherVisits = toscalar(
    OtherWithClosedEvents
    | summarize by operation_Id
    | count
);
print
    TotalOtherVisits = TotalOtherVisits,
    ClosedOtherVisits = ClosedOtherVisits,
    Rate = round(iif(TotalOtherVisits > 0, todouble(ClosedOtherVisits) / todouble(TotalOtherVisits) * 100, 0.0), 1)

let SearchPageVisits =
    pageViews
    | where timestamp {TimeRange}
    | where url contains "/search"
    | summarize by operation_Id;
let TotalVisits = toscalar(SearchPageVisits | count);
let HintActedVisits = toscalar(
    customEvents
    | where timestamp {TimeRange}
    | where name == "search"
    | where isnotempty(tostring(customDimensions.caseNumber))
    | summarize
        hadExcluded = countif(tostring(customDimensions.excludeClosedCases) == "true"),
        thenIncluded = countif(tostring(customDimensions.excludeClosedCases) == "false")
        by operation_Id
    | where hadExcluded > 0 and thenIncluded > 0
    | join kind=inner SearchPageVisits on operation_Id
    | count
);
print
    TotalVisits = TotalVisits,
    HintActedVisits = HintActedVisits,
    HintActedRate = round(iif(TotalVisits > 0, todouble(HintActedVisits) / todouble(TotalVisits) * 100, 0.0), 1)

let firstSearch = customEvents
| where timestamp {TimeRange}
| where name == "First Search Action"
| project session_Id, startTime = timestamp;
let includeClosed = customEvents
| where timestamp {TimeRange}
| where name in ("Include Closed Cases Link Clicked", "Include Closed Cases Checkbox Checked")
| project session_Id, triggerTime = timestamp, TriggerType = iif(name contains "Link", "Hint Link", "Manual Checkbox");
firstSearch
| join kind=inner (includeClosed) on session_Id
| where triggerTime > startTime
| extend durationSeconds = datetime_diff('second', triggerTime, startTime)
| summarize ['Avg Time to Include Closed (sec)'] = round(avg(durationSeconds), 1) by TriggerType

let SearchPageVisits =
    pageViews
    | where timestamp {TimeRange}
    | where url contains "/search"
    | summarize by operation_Id;
let TotalVisits = toscalar(SearchPageVisits | count);
// Proxy: case number search with excludeClosedCases=true that returns no open results
// We detect this via searches where excludeClosedCases=true + caseNumber is set,
// then a subsequent search in same session with excludeClosedCases=false (user acted on the hint)
let HintActedVisits = toscalar(
    customEvents
    | where timestamp {TimeRange}
    | where name == "search"
    | where isnotempty(tostring(customDimensions.caseNumber))
    | summarize
        hadExcluded = countif(tostring(customDimensions.excludeClosedCases) == "true"),
        thenIncluded = countif(tostring(customDimensions.excludeClosedCases) == "false")
        by operation_Id
    | where hadExcluded > 0 and thenIncluded > 0
    | join kind=inner SearchPageVisits on operation_Id
    | count
);
print
    TotalVisits = TotalVisits,
    HintActedVisits = HintActedVisits,
    HintActedRate = round(iif(TotalVisits > 0, todouble(HintActedVisits) / todouble(TotalVisits) * 100, 0.0), 1)
